/**
 * @param {string} s
 * @return {string}
 */
function solve(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
    const n = s.length;

    // 1. Collect all vowels and their original indices
    const vowelInfo = []; // [{char: 'a', index: 0}, ...]
    const charCounts = {};
    const firstAppearance = {};

    for (let i = 0; i < n; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            vowelInfo.push({ char: char, index: i });

            // Count frequency
            charCounts[char] = (charCounts[char] || 0) + 1;

            // Record first appearance index
            if (firstAppearance[char] === undefined) {
                firstAppearance[char] = i;
            }
        }
    }

    // 2. Determine the sorted order of the unique vowels based on the rules
    // The sorting criteria are:
    // 1. Frequency (descending)
    // 2. First appearance index (ascending, for ties in frequency)

    const uniqueVowels = Object.keys(charCounts).sort((a, b) => {
        const countA = charCounts[a];
        const countB = charCounts[b];
        const firstA = firstAppearance[a];
        const firstB = firstAppearance[b];

        // Rule 1: Frequency non-increasing (descending)
        if (countA !== countB) {
            return countB - countA; // Higher frequency comes first
        }
        // Rule 2: First appearance position (ascending)
        return firstA - firstB; // Earlier appearance comes first
    });

    // 3. Construct the result array/string
    const resultArr = s.split('');

    // Map to store the required sequence of vowels
    const replacementVowels = [];
    for (const vowel of uniqueVowels) {
        const count = charCounts[vowel];
        for (let k = 0; k < count; k++) {
            replacementVowels.push(vowel);
        }
    }

    // Place the sorted vowels back into the original vowel positions
    let replacementIndex = 0;
    for (let i = 0; i < n; i++) {
        if (vowels.has(s[i])) {
            // This position must be filled by the next vowel in the sorted sequence
