import scala.collection.mutable

object Solution {
  def s(s: String): String = {
    val vowels = Set('a', 'e', 'i', 'o', 'u')
    val n = s.length

    // 1. Collect all vowels and their original indices, count frequencies, and record first appearance
    val charCounts = mutable.Map[Char, Int]()
    val firstAppearance = mutable.Map[Char, Int]()
    val vowelPositions = mutable.ListBuffer[Int]() // Stores indices where vowels appear

    for (i <- 0 until n) {
      val char = s(i)
      if (vowels.contains(char)) {
        vowelPositions += i

        // Count frequency
        charCounts(char) = charCounts.getOrElse(char, 0) + 1

        // Record first appearance index
        if (!firstAppearance.contains(char)) {
          firstAppearance(char) = i
        }
      }
    }

    // 2. Determine the sorted order of the unique vowels based on the rules

    // Get unique vowels present in the string
    val uniqueVowels = charCounts.keys.toSeq

    // Sort criteria:
    // 1. Frequency (descending)
    // 2. First appearance index (ascending, for ties in frequency)

    val sortedUniqueVowels = uniqueVowels.sortBy { vowel =>
      // Return a tuple for comparison: (-frequency, firstAppearanceIndex)
      // Negating frequency ensures descending order when sorting ascendingly
      (-charCounts(vowel), firstAppearance(vowel))
    }.map(_._1) // We only need the vowel character, the tuple sorting is implicit

    // 3. Construct the replacement sequence of vowels
    val replacementVowels = mutable.ListBuffer[Char]()
    for (vowel <- sortedUniqueVowels) {
      val count = charCounts(vowel)
      for (k <- 1 to count) {
        replacementVowels += vowel
      }
    }

    // 4. Place the sorted vowels back into the original vowel positions
    val resultChars = new Array[Char](n)
    val originalChars = s.toCharArray

    // Copy non-vowels directly
    for (i <- 0 until n) {
      val char = originalChars(i)
      if (!vowels.contains(char)) {
        resultChars(i) = char
      }
    }

    // Place sorted vowels into vowel positions
    val replacementVowelSequence = replacementVowels.toSeq
    for (i <- 0 until vowelPositions.length) {
      val originalIndex = vowelPositions(i)
      resultChars(originalIndex) = replacementVowelSequence(i)
    }

    new String(resultChars)
  }
}
