import scala.collection.mutable

object Solution {
  def s(s: String): String = {
    val vowels = Set('a', 'e', 'i', 'o', 'u')
    val n = s.length

    // 1. Collect counts and first appearance index for each vowel
    val charCounts = mutable.Map[Char, Int]()
    val firstAppearance = mutable.Map[Char, Int]()

    for (i <- 0 until n) {
      val char = s.charAt(i)
      if (vowels.contains(char)) {
        // Count frequency
        charCounts.update(char, charCounts.getOrElse(char, 0) + 1)

        // Record first appearance index
        if (!firstAppearance.contains(char)) {
          firstAppearance.put(char, i)
        }
      }
    }

    // Get unique vowels present in s
    val uniqueVowels = charCounts.keys.toSeq

    // 2. Determine the sorted order of unique vowels
    // Sorting criteria:
    // 1. Frequency (descending)
    // 2. First appearance index (ascending, for ties in frequency)

    val sortedVowels = uniqueVowels.sortBy { vowel =>
      // Return a tuple used for comparison: (-frequency, first_appearance_index)
      // Sorting ascending on this tuple achieves:
      // - Descending frequency (because we negate it)
      // - Ascending first appearance index
      (-charCounts(vowel), firstAppearance(vowel))
    }

    // 3. Construct the sequence of vowels to be placed back
    val replacementVowels = mutable.ListBuffer[Char]()
    for (vowel <- sortedVowels) {
      val count = charCounts(vowel)
      for (_ <- 0 until count) {
        replacementVowels.append(vowel)
      }
    }

    // 4. Place the sorted vowels back into the original vowel positions
    val resultChars = new Array[Char](n)
    val vowelIndices = mutable.ListBuffer[Int]()

    for (i <- 0 until n) {
      val char = s.charAt(i)
      if (vowels.contains(char)) {
        vowelIndices.append(i)
      }
    }

    // Copy non-vowels directly
    for (i <- 0 until n) {
      val char = s.charAt(i)
      if (!vowels.contains(char)) {
        resultChars(i) = char
      }
    }

    // Place sorted vowels into original vowel spots
    for (k <- 0 until vowelIndices.length) {
      val originalIndex = vowelIndices(k)
      val replacementChar = replacementVowels(k)
      resultChars(originalIndex) = replacementChar
    }

    new String(resultChars)
  }
}
